/**
 * API Client с кэшированием и оптимизацией
 */
import axios from 'axios';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const client = axios.create({
  baseURL: API_URL,
  timeout: 30000,
});

// Request interceptor - добавляем токен
client.interceptors.request.use(config => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// Response interceptor - обработка ошибок
client.interceptors.response.use(
  response => response.data,
  error => {
    if (error.response?.status === 401) {
      localStorage.removeItem('token');
      window.location.href = '/login';
    }
    throw error.response?.data?.error || error.message;
  }
);

// Cache для GET запросов
const cache = new Map();

export const api = {
  // Auth
  register: (email, password, fullName) =>
    client.post('/register', { email, password, fullName }),
  
  login: (email, password) =>
    client.post('/login', { email, password }),
  
  // Projects
  getProjects: async () => {
    const key = 'projects-list';
    if (cache.has(key)) return cache.get(key);
    const data = await client.get('/projects');
    cache.set(key, data);
    return data;
  },
  
  getProject: async (id) => {
    const key = `project-${id}`;
    if (cache.has(key)) return cache.get(key);
    const data = await client.get(`/projects/${id}`);
    cache.set(key, data);
    return data;
  },
  
  createProject: (description, template) => {
    cache.delete('projects-list'); // Инвалидировать кэш
    return client.post('/projects', { description, template });
  },
  
  updateProject: (id, updates) => {
    cache.delete('projects-list');
    cache.delete(`project-${id}`);
    return client.put(`/projects/${id}`, updates);
  },
  
  deleteProject: (id) => {
    cache.delete('projects-list');
    cache.delete(`project-${id}`);
    return client.delete(`/projects/${id}`);
  },
  
  downloadProject: (id) => {
    return client.get(`/projects/${id}/download`, { responseType: 'blob' });
  },
  
  clearCache: () => cache.clear(),
};

export default client;
